import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { FiSettings, FiUser, FiLock, FiBell, FiMoon, FiSun } from 'react-icons/fi';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

const Settings = () => {
  const { user, updateUser } = useAuth(); // make sure updateUser exists in AuthContext

  const [darkMode, setDarkMode] = useState(() => {
    const savedTheme = localStorage.getItem('darkMode');
    return savedTheme ? JSON.parse(savedTheme) : true;
  });

  const [notifications, setNotifications] = useState(() => {
    const savedNotifications = localStorage.getItem('notifications');
    return savedNotifications
      ? JSON.parse(savedNotifications)
      : {
          assignments: true,
          exams: true,
          grades: true,
          announcements: false,
        };
  });

  const [profile, setProfile] = useState({
    name: user?.name || '',
    email: user?.email || '',
  });

  const [passwords, setPasswords] = useState({
    currentPassword: '',
    newPassword: '',
    confirmPassword: '',
  });

  // Apply dark/light theme
  useEffect(() => {
    document.documentElement.setAttribute('data-theme', darkMode ? 'dark' : 'light');
    localStorage.setItem('darkMode', JSON.stringify(darkMode));
  }, [darkMode]);

  // Save notifications
  useEffect(() => {
    localStorage.setItem('notifications', JSON.stringify(notifications));
  }, [notifications]);

  // Update profile when user changes
  useEffect(() => {
    if (user) {
      setProfile({
        name: user.name || '',
        email: user.email || '',
      });
    }
  }, [user]);

  const handleProfileSave = async () => {
    try {
      const updatedProfile = {
        ...user,
        name: profile.name,
        email: profile.email,
      };

      // Optional: save in localStorage for demo
      localStorage.setItem('userProfile', JSON.stringify(updatedProfile));

      // If your AuthContext has updateUser, update global auth state
      if (updateUser) {
        updateUser(updatedProfile);
      }

      // If you have backend, call API here:
      /*
      const res = await fetch('/api/user/profile', {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(profile),
      });

      if (!res.ok) throw new Error('Failed to update profile');
      */

      toast.success('Profile updated successfully!');
    } catch (error) {
      toast.error(error.message || 'Failed to update profile');
    }
  };

  const handlePasswordSave = async () => {
    const { currentPassword, newPassword, confirmPassword } = passwords;

    if (!currentPassword || !newPassword || !confirmPassword) {
      return toast.error('Please fill all password fields');
    }

    if (newPassword.length < 6) {
      return toast.error('New password must be at least 6 characters');
    }

    if (newPassword !== confirmPassword) {
      return toast.error('New passwords do not match');
    }

    try {
      // Real password change requires backend API
      const res = await fetch('/api/user/change-password', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          currentPassword,
          newPassword,
        }),
      });

      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        throw new Error(data.message || 'Failed to change password');
      }

      setPasswords({
        currentPassword: '',
        newPassword: '',
        confirmPassword: '',
      });

      toast.success('Password changed successfully!');
    } catch (error) {
      toast.error(error.message || 'Failed to change password');
    }
  };

  const handleFormSubmit = (e) => {
    e.preventDefault(); // Prevent page reload
  };

  const Section = ({ icon, title, children }) => (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      style={{
        background: 'var(--card-bg)',
        border: '1px solid var(--border)',
        borderRadius: '16px',
        padding: '24px',
        marginBottom: '20px',
      }}
    >
      <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '20px' }}>
        <span style={{ color: '#667eea', fontSize: '1.1rem' }}>{icon}</span>
        <h3 style={{ margin: 0, fontSize: '1rem', fontWeight: '600' }}>{title}</h3>
      </div>
      {children}
    </motion.div>
  );

  const inputStyle = {
    width: '100%',
    padding: '10px 14px',
    background: 'rgba(255,255,255,0.05)',
    border: '1px solid var(--border)',
    borderRadius: '10px',
    color: 'var(--text-primary)',
    fontSize: '0.9rem',
    marginBottom: '12px',
    boxSizing: 'border-box',
  };

  const Toggle = ({ checked, onChange }) => (
    <div
      onClick={() => onChange(!checked)}
      style={{
        width: '44px',
        height: '24px',
        borderRadius: '12px',
        background: checked ? '#667eea' : 'rgba(255,255,255,0.1)',
        cursor: 'pointer',
        position: 'relative',
        transition: 'background 0.3s',
        flexShrink: 0,
      }}
    >
      <div
        style={{
          position: 'absolute',
          top: '3px',
          left: checked ? '23px' : '3px',
          width: '18px',
          height: '18px',
          borderRadius: '50%',
          background: '#fff',
          transition: 'left 0.3s',
        }}
      />
    </div>
  );

  return (
    <div style={{ padding: '30px', maxWidth: '650px', margin: '0 auto' }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '8px' }}>
        <FiSettings size={24} color="#667eea" />
        <h1 style={{ fontSize: '1.8rem', fontWeight: '700', margin: 0 }}>Settings</h1>
      </div>

      <p style={{ color: 'var(--text-muted)', marginBottom: '30px' }}>
        Manage your account preferences
      </p>

      <Section icon={<FiUser />} title="Profile Information">
        <input
          style={inputStyle}
          value={profile.name}
          onChange={(e) => setProfile({ ...profile, name: e.target.value })}
          placeholder="Full Name"
        />
        <input
          style={inputStyle}
          value={profile.email}
          onChange={(e) => setProfile({ ...profile, email: e.target.value })}
          placeholder="Email"
          type="email"
        />
        <button
          onClick={handleProfileSave}
          style={{
            padding: '10px 24px',
            background: 'var(--gradient-primary)',
            border: 'none',
            borderRadius: '10px',
            color: '#fff',
            fontWeight: '600',
            cursor: 'pointer',
            fontSize: '0.9rem',
          }}
        >
          Save Changes
        </button>
      </Section>

      <Section icon={<FiLock />} title="Change Password">
        <form onSubmit={handleFormSubmit}>
          <input
            style={inputStyle}
            type="password"
            placeholder="Current Password"
            value={passwords.currentPassword}
            onChange={(e) =>
              setPasswords({ ...passwords, currentPassword: e.target.value })
            }
          />
          <input
            style={inputStyle}
            type="password"
            placeholder="New Password"
            value={passwords.newPassword}
            onChange={(e) =>
              setPasswords({ ...passwords, newPassword: e.target.value })
            }
          />
          <input
            style={inputStyle}
            type="password"
            placeholder="Confirm New Password"
            value={passwords.confirmPassword}
            onChange={(e) =>
              setPasswords({ ...passwords, confirmPassword: e.target.value })
            }
          />
          <button
            type="submit"
            onClick={handlePasswordSave}
            style={{
              padding: '10px 24px',
              background: 'var(--gradient-primary)',
              border: 'none',
              borderRadius: '10px',
              color: '#fff',
              fontWeight: '600',
              cursor: 'pointer',
              fontSize: '0.9rem',
            }}
          >
            Update Password
          </button>
        </form>
      </Section>

      <Section icon={<FiBell />} title="Notification Preferences">
        {Object.entries(notifications).map(([key, val]) => (
          <div
            key={key}
            style={{
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              marginBottom: '14px',
            }}
          >
            <span style={{ textTransform: 'capitalize', fontSize: '0.9rem' }}>
              {key} notifications
            </span>
            <Toggle
              checked={val}
              onChange={(v) =>
                setNotifications({ ...notifications, [key]: v })
              }
            />
          </div>
        ))}
      </Section>

      <Section icon={darkMode ? <FiMoon /> : <FiSun />} title="Appearance">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <span style={{ fontSize: '0.9rem' }}>Dark Mode</span>
          <Toggle checked={darkMode} onChange={setDarkMode} />
        </div>
      </Section>
    </div>
  );
};

export default Settings;
